+/*
+ * @test
+ * @bug 8380666
+ * @summary Test that the substitutability check loads the klass pointer from
+ *          the right location when UseCompactObjectHeaders is enabled.
+ * @enablePreview
+ * @run junit ${test.main.class}
+ * @run junit/othervm -XX:+UnlockDiagnosticVMOptions -Xcomp -XX:TieredStopAtLevel=1 -XX:+UseCompactObjectHeaders
+ *                    -XX:CompileCommand=compileonly,*TestSubstitutabilityWithCOH::acmp
+ *                    ${test.main.class}
+ */
+
+import java.util.stream.Stream;
+
+import org.junit.jupiter.params.ParameterizedTest;
+import org.junit.jupiter.params.provider.Arguments;
+import org.junit.jupiter.params.provider.MethodSource;
+
+public class TestSubstitutabilityWithCOH {
+    static value class EmptyValue {
+    }
+
+    Object obj;
+
+    // This is needed to trigger heap placement of the EmptyValue object in such
+    // a way that there are garbage bits at the location where the substitutability
+    // check is incorrectly reading the klass pointer from. Brittle but all we got.
+    static Stream<Arguments> arguments() {
+        return Stream.of(Arguments.of(new EmptyValue()));
+    };
+
+    @ParameterizedTest
+    @MethodSource("arguments")
+    public void test(Object expected) {
+        obj = expected;
+        acmp(new EmptyValue());
+    }
+
+    public void acmp(Object expected) {
+        if (obj != expected) {
+            throw new RuntimeException("Unexpected result");
+        }
+    }
+}
